function encodeSVG(svg) {
    return encodeURIComponent(svg)
        .replace(/'/g, "%27")
        .replace(/"/g, "%22")
}

function getThemeColor() {
    const themeColorsBySection = {
        workbench: '--color-medium-secondary',
        community: '--color-accent-medium',
        account: '--color-medium-primary',
        academy: '--color-accent-dark',
        office: '--color-accent-medium',
        wiki: '--color-medium-primary',
        default: '--color-medium-primary',
    }

    return getComputedStyle(document.body)
        .getPropertyValue(themeColorsBySection[props.section] ?? themeColorsBySection.default)
        .trim()
}

function getPatternOpacity() {
    const opacityBySection = {
        workbench: 0.5,
        community: 0.25,
        account: 0.125,
        academy: 0.125,
        office: 0.25,
        wiki: 0.125,
        default: 0,
    }

    return opacityBySection[props.section] ?? opacityBySection.default
}

